#include <bits/stdc++.h>
using namespace std;

int main() {
    int x, y, k, n;
    queue<int> q;
    cin >> x >> y >> k;
    n = x + y;
    for (int i = 1; i <= n; i++) q.push(i);
    while (q.size() > x) {
        for (int i = 1; i < k; i++) {
            int tmp = q.front();
            q.pop();
            q.push(tmp);
        }
        q.pop();
    }
    int a[105], l = 0;
    for (int i = 1; i <= x; i++) {
        int tmp = q.front();
        q.pop();
        q.push(tmp);
        a[l++] = tmp;
    }
    sort(a, a + l);
    for (int i = 0; i < l; i++) {
        cout << a[i] << ' ';
    }
    return 0;
}
